# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
import json
from eth_account.messages import encode_defunct
from web3 import Web3, HTTPProvider

app = Flask(__name__)
w3 = Web3(HTTPProvider('http://localhost:8545'))  # Replace with your Ethereum node URL

@app.route('/verify', methods=['POST'])
def verify_signature():
    data = json.loads(request.data)
    
    if 'message' not in data or 'signature' not in data:
        return jsonify({"error": "Missing message or signature"}), 400
        
    recovered_address = w3.eth.account.recoverHash(encode_defunct(text=data['message']).hash, signature=data['signature'])
    
    if recovered_address == data['address'].lower():
        return jsonify({"verified": True}), 200
    else:
        return jsonify({"verified": False}), 401

if __name__ == "__main__":
    app.run(port=5000)